// Minimal typed declarations for shadcn/ui primitives.
  // shadcn primitives are vendored, generated by the shadcn CLI, and use
  // `React.forwardRef` without explicit prop generics — which makes JS
  // checkJs infer them as `RefAttributes<any>` and reject every children /
  // className / onClick spread on every consumer page.
  // Rather than rewrite each vendored primitive with hand-written prop types,
  // the jsconfig `paths` mapping redirects `@/components/ui/*` imports to
  // this declaration file at typecheck time. Runtime imports are unaffected
  // (Vite resolves the real .jsx files normally) and the consuming pages are
  // still type-checked — the components themselves are typed as React
  // components that accept the prop bags shadcn primitives are designed for.
  import * as React from 'react';

